function t(n){return(n/100).toFixed(2)}function r(n){if(n<60)return`${n}分钟`;const o=Math.floor(n/60),e=n%60;return e>0?`${o}小时${e}分钟`:`${o}小时`}function a(n){return n<1e3?`${Math.round(n)}m`:`${(n/1e3).toFixed(1)}km`}function c(n){return{pending:"待处理",borrowed:"租借中",租借中:"租借中",completed:"已完成",cancelled:"已取消",pending_compensation:"待赔付",compensated:"已赔付"}[n]||n}function d(n){return{pending:"#ff976a",borrowed:"#07c160",租借中:"#07c160",completed:"#969799",cancelled:"#969799",pending_compensation:"#ee0a24",compensated:"#969799"}[n]||"#969799"}export{c as a,t as b,r as c,a as f,d as o};
